ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT (AVG(?agerating_a) AS ?agg) (AVG(?criticalrating_a) AS ?agg2) WHERE {
  ?rating a :Rating .
  ?movie a :Movie .
  ?rating p:hasMovie ?movie .
  ?genre a :Genre .
  ?movie p:hasGenre ?genre .
  ?genre p:name ?name_f .
  ?rating p:ageRating ?agerating_a .
  ?rating p:criticalRating ?criticalrating_a .
  FILTER(STR(?name_f) = "Action")
} }
  component: { SELECT (AVG(?agerating_a) AS ?agg) WHERE {
  ?rating a :Rating .
  ?movie a :Movie .
  ?rating p:hasMovie ?movie .
  ?genre a :Genre .
  ?movie p:hasGenre ?genre .
  ?genre p:name ?name_f .
  ?rating p:ageRating ?agerating_a .
  FILTER(STR(?name_f) = "Action")
} }
  component_2: { SELECT (AVG(?criticalrating_a) AS ?agg) WHERE {
  ?rating a :Rating .
  ?movie a :Movie .
  ?rating p:hasMovie ?movie .
  ?genre a :Genre .
  ?movie p:hasGenre ?genre .
  ?genre p:name ?name_f .
  ?rating p:criticalRating ?criticalrating_a .
  FILTER(STR(?name_f) = "Action")
} }
}

PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  component: { SELECT ?movieid ?criticalrating WHERE {
  ?rating a :Rating .
  ?movie a :Movie .
  ?rating p:hasMovie ?movie .
  ?rating p:movieId ?movieid .
  ?rating p:criticalRating ?criticalrating .
  ?rating p:criticalRating ?criticalrating_o .
}
ORDER BY DESC(?criticalrating_o) }
  component_2: { SELECT ?movieid ?agerating WHERE {
  ?rating a :Rating .
  ?movie a :Movie .
  ?rating p:hasMovie ?movie .
  ?rating p:movieId ?movieid .
  ?rating p:ageRating ?agerating .
  ?rating p:ageRating ?agerating_o .
}
ORDER BY DESC(?agerating_o) }
  full: { SELECT ?movieid ?agerating ?criticalrating WHERE {
  ?rating a :Rating .
  ?movie a :Movie .
  ?rating p:hasMovie ?movie .
  ?rating p:movieId ?movieid .
  ?rating p:ageRating ?agerating .
  ?rating p:criticalRating ?criticalrating .
  ?rating p:ageRating ?agerating_o .
  ?rating p:criticalRating ?criticalrating_o .
}
ORDER BY ASC(?agerating_o) DESC(?criticalrating_o) }
}
